        flags |= F_GeneratedStack;
        _stack = kmalloc(_stacksize);
        if (_stack == nullptr) {
            kout[Fault] << "ERR_Kmalloc stack" << endl;
        }
    }
    MemsetT<char>((char *)_stack, 0, _stacksize);
    stack = _stack, stacksize = _stacksize;
}

