        __sync_synchronize();
        // kout[DeBug]<<"TryLock "<<spinLock<<endl;
        return !old;
    }

    inline void unlock()
    {
        __sync_synchronize();
        __sync_lock_release(&spinLock);
        // kout[DeBug]<<"unLock "<<spinLock<<endl;
    }

    inline void lock()
    {

        // kout[DeBug]<<"Lock "<<spinLock<<endl;
        while (__sync_lock_test_and_set(&spinLock, 1) != 0)
        {
        }
            ;
        __sync_synchronize();
    }
    inline void init()
    {
        spinLock = 0;
        // kout[DeBug]<<"init Lock "<<spinLock<<endl;
