template <typename T>
void MemsetT(T* dst, const T& val, unsigned long long count)
{
    if (dst == nullptr || count == 0)
        return;
    T* end = dst + count;
    while (dst != end)
        *dst++ = val;
}

template <typename T>
void MemcpyT(T* dst, const T* src, unsigned long long count)
{
    if (dst == nullptr || src == nullptr || dst == src || count == 0)
        return;
    T* end = dst + count;
    while (dst != end)
        *dst++ = *src++;
}

